'use strict';

// The ONLY place a Lambda should look to find out who is calling it.
// The HTTP API's Cognito JWT authorizer has already verified the token's
// signature/issuer/audience before this code ever runs - we just read the
// claim it attached. Never trust a client-supplied userId in the body.

class UnauthorizedError extends Error {}

function getUserSub(event) {
  const sub = event?.requestContext?.authorizer?.jwt?.claims?.sub;
  if (!sub) {
    throw new UnauthorizedError('Missing verified sub claim on request');
  }
  return sub;
}

module.exports = { getUserSub, UnauthorizedError };
